import React from 'react';
import {Container, Row, Col} from 'react-bootstrap';
import 'bootstrap/dist/css/bootstrap.min.css';
import "./SkillsSection.css";
import react from "./assets/react.png";
import flutter from "./assets/flutter.png";
import photoshop from "./assets/photoshop.png";

 
const SkillsSection = () => { 
    return(
        <Container fluid className="skills-container">
           <div>  
           <Row className="wrapper-row-1">
                <Col xs={6} className="col-1"><img src={react} height="200" width="200"/></Col>
                <Col xs={6} className="col-2">
                    <Row className="col-1-row-1 skill-heading skill1"><h1>React</h1></Row>
                    <Row className="col-1-row-3 skill-body"><p>Sign Up for your free online account enter email and any password.</p></Row>
                </Col>
                <Col xs={6} ></Col> 
            </Row>

            <Row className="wrapper-row-2">
                <Col xs={6} className="col-2">
                    <Row className="col-1-row-1 skill-heading skill2"><h1>Flutter</h1></Row>
                    <Row className="col-1-row-3 skill-body"><p>Sign Up for your free online account enter email and any password.</p></Row>
                </Col>
                <Col xs={6} className="col-1"><img src={flutter} height="200" width="200"/></Col>
    
            </Row>
            <Row className="wrapper-row-3">
                <Col xs={6} className="col-1"><img src={photoshop} height="200" width="200"/></Col>
                <Col xs={6} className="col-2">
                <Row className="col-1-row-1 skill-heading skill3"><h1>Photoshop</h1></Row>    
                <Row className="col-1-row-3 skill-body"><p>Sign Up for your free online account enter email and any password.</p></Row>
                </Col>
            </Row>
            </div>
        </Container>
    )
}
export default SkillsSection;


