import React from 'react'
import {Container, Button, Row, Col } from 'react-bootstrap';
import 'bootstrap/dist/css/bootstrap.min.css';
import HeroImg from "./assets/hero.png"
import eleStar from "./assets/star.png"
import "./HeroSection.css"; 



const HeroSection = () => {
    return (
        <Container fluid className="hero-container" >
          <Row>
                <Col className="hero-col">
                    <img className="hero-image" src={HeroImg} height="400" width="500"/>
                </Col>
                <Col className="hero-col">
                    <div className="hero-div">
                        <img className="elements" src={eleStar} height="100" width="100"/>
                        <h1>Mobashshir Iqbal </h1>
                        <div className="pad"></div>
                        <p>A Tech enthusiast who is pursuing his BTech.
                        Interested in graphic design and app development. Created several beautiful apps designs and published.
                        </p>
                    </div>
                </Col>
            </Row>  
        </Container>
    );
}

export default HeroSection;

