import React from 'react';
import {Container, Row, Col, Form} from 'react-bootstrap';
import 'bootstrap/dist/css/bootstrap.min.css';
import "./ContactPage.css";
import sample from './assets/talk.mp4';

const ContactPage = () =>{
    return(
        
            <div className="clippath-container" >
                <Row>
                    <Col className="form-section" >
                        <div className="form-wrapper"> 
                        <h1>Get In Touch</h1>
                        <Form.Group controlId="exampleForm.ControlInput1">
                            <Form.Control className="name" type="text" placeholder="Name"/>
                        </Form.Group>
                        <Form.Group controlId="exampleForm.ControlInput1">
                            <Form.Control className="email" type="email" placeholder="Email: name@example.com"/>
                        </Form.Group>
                        <Form.Group controlId="exampleForm.ControlTextarea1">
                            <Form.Control className="text-area" as="textarea" rows={3} placeholder="Write something" />
                        </Form.Group>
                        </div>
                    </Col>

                    <Col className='video-col'>
                        <video className='videoTag2' autoPlay loop muted >
                        <source src={sample} type='video/mp4' /> 
                        </video> 
                    </Col>
                   
                </Row>
            </div>
        
    )
}

export default ContactPage;